examples.code:
PDA for balanced 0^n 1^n:

Q = {q0, q1, q2}
Σ = {0, 1}
Γ = {0, Z0}
F = {q2} (or empty for empty stack acceptance)

Transition Function δ:

// Phase 1: Push all 0's onto stack
δ(q0, 0, Z0) = {(q0, 0Z0)}
δ(q0, 0, 0) = {(q0, 00)}

// Transition from pushing to checking
δ(q0, 1, 0) = {(q1, 0)}

// Phase 2: Match 1's by popping 0's
δ(q1, 1, 0) = {(q1, ε)}

// Accept when input exhausted and stack empty
δ(q1, ε, Z0) = {(q2, Z0)} // Optional final state

Acceptance: Stack empty (Z0 removed)

PDA for palindromes L = {ww^R | w ∈ {0,1}*}:

Q = {q_push, q_check, q_accept}
Σ = {0, 1}
Γ = {0, 1, Z0}

// Push Phase: Push input symbols
δ(q_push, 0, Z0) = {(q_push, 0Z0)}
δ(q_push, 0, 0) = {(q_push, 00)}
δ(q_push, 0, 1) = {(q_push, 01)}
δ(q_push, 1, Z0) = {(q_push, 1Z0)}
δ(q_push, 1, 0) = {(q_push, 10)}
δ(q_push, 1, 1) = {(q_push, 11)}

// Guess middle - non-deterministic ε-transition
δ(q_push, ε, X) = {(q_check, X)} for X ∈ Γ

// Check Phase: Pop and compare
δ(q_check, 0, 0) = {(q_check, ε)}
δ(q_check, 1, 1) = {(q_check, ε)}

// Accept when stack empty
δ(q_check, ε, Z0) = {(q_accept, Z0)}

function simulate_PDA(PDA M, input w):
 // M = (Q, Σ, Γ, δ, q0, Z0, F)

 configurations = [(q0, w, Z0)] // Initial ID

 while configurations not empty:
 // Choose one configuration (non-deterministic choice)
 (q, input_remaining, stack) = pop(configurations)

 if input_remaining == ε and stack == ε:
 return ACCEPT // Empty input, empty stack

 if input_remaining == ε and q ∈ F:
 return ACCEPT // Input consumed, in accepting state

 // Get next configurations based on δ
 a = first symbol of input_remaining (or ε)
 X = top of stack (or ε)

 for each (p, γ) in δ(q, a, X):
 new_input = input_remaining without first symbol
 new_stack = γ + stack without top
 add (p, new_input, new_stack) to configurations

 return REJECT // No accepting configuration found
